var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"샤레이드에서도 많은 일이 있었던 모양이군.","JPN":"シャレードでも色々あったようだな。","ENG":"It seems a great deal happened in Charade as well.","TWN":"看來在查雷德也發生了不少事呢。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……일단은 보고한 대로야.","JPN":"……とりあえず、報告したとおりだ。","ENG":"...For now, it's just as I reported.","TWN":"……總之，和報告的一樣。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"프론트 베이에서 인계 받았던 선로전환기는 파괴되었고. 유산은 소실되었어.","JPN":"フロントベイから引き渡された線路転換器は破壊され、遺産は消失した。","ENG":"The Track Switcher we received from Front Bay was destroyed, and the Legacy was lost.","TWN":"在前灣交接的線路轉換器被破壞，遺產也已下落不明。"},"stage":{"bg":"OMEN_CHARADE_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"유산을 분실한 이상, 다음 도시에서는 전환기의 도움을 받을 수 없겠지.","JPN":"遺産を失った以上、次の都市では転換器の力を借りることはできない。","ENG":"With the Legacy gone, we won't be able to rely on the Switcher in the next city.","TWN":"既然遺產遺失，在下一座城市也無法再借助轉換器的力量了吧。"},"stage":{"bg":"OMEN_CHARADE_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어차피 전조 현상이 발생한 순간부터 예정된 일이었어.","JPN":"どのみち、前兆現象が発生した瞬間から決まっていた結果だ。","ENG":"It was inevitable from the moment the omen phenomenon began.","TWN":"反正從前兆現象發生的那一刻起，這一切就已經注定好了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그나마 황금향의 유산이 있었기에 조금이나마 시간을 벌 수 있었던 것이겠지.","JPN":"それでも黄金郷の遺産があったから、少しでも時間を稼げたんだ。","ENG":"At least the Golden Vale's Legacy bought us a little time.","TWN":"但至少因為黃金鄉的遺產，我們才爭取到一點時間。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그로 인해, 우리는 많은 사람들을 구할 수 있었어.","JPN":"おかげで我々は多くの人を助けることができた。","ENG":"Because of that, we were able to save many lives.","TWN":"也因此救了許多人。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 다음 도시에 대한 안배도 이미 마쳐두었네.","JPN":"そして、次の都市のための布石もすでに打ってある。","ENG":"And preparations for the next city are already complete.","TWN":"而且也已經完成對下座城市的安排了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"최고 관리자…….","JPN":"最高管理者……","ENG":"Supreme Administrator...","TWN":"最高管理者……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"우리 관리국에게 승산이 있을까?","JPN":"私たち管理局に勝ち目はあるだろうか？","ENG":"Do we really stand a chance?","TWN":"我們管理局真的還有勝算嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"샤레이드에는 S급 카운터가 셋이나 있었어. 그 외 전력들도 충분히 강했지.","JPN":"シャレードにはS級カウンターが3人もいた。他の戦力も皆十分に強かった。","ENG":"There were three Grade S Counters in Charade, and the rest of our forces were strong as well.","TWN":"查雷德有三名S級制裁者，其餘戰力也相當充足。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"리하르트가 준비해둔 재난 대응 매뉴얼도 손색이 없었어.","JPN":"リヒャルトが用意しておいた災害対応マニュアルも、非の打ち所がなかった。","ENG":"The disaster response manual Richard prepared was also flawless.","TWN":"理查準備的災害應對手冊也沒有缺點。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"모든 조건이 최선이었는데도…….","JPN":"どれも最高の条件だったにもかかわらず……","ENG":"Every condition was ideal, and yet...","TWN":"所有條件都已經是最佳情況了……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"결국 우리는 그 무엇도 막아내지 못했잖아?","JPN":"結局私たちは何も止められなかったじゃないか。","ENG":"In the end, we couldn't stop anything.","TWN":"可是最終我們什麼都阻止不了，不是嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"피할 수 없는 침식 재난 앞에서, 우리가 정말로 무언가를 바꿀 수 있을까?","JPN":"避けられない侵食災害の前で、私たちは本当に、何かを変えられるのか？","ENG":"Faced with an unavoidable Corruption disaster, can we truly change anything?","TWN":"面對無法逃避的侵蝕災害，我們真的能改變什麼嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"글쎄, 하지만 마지막까지 노력해 봐야지.","JPN":"そうだな、でも最後までもがいてみないとな。","ENG":"Who knows. But we have to try until the very end.","TWN":"誰知道呢？但我們還是得努力到最後。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"설령, 그것이 누군가에 의해 철저히 만들어진 기적이라고 할지라도 말이야.","JPN":"たとえそれが、誰かによって徹底的に作られた奇跡だとしても。","ENG":"Even if that hope is nothing more than a miracle meticulously manufactured by someone.","TWN":"即便那是一場徹底被某人安排好的奇蹟。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"만들어진 기적이라고……?","JPN":"作られた奇跡……？","ENG":"A manufactured miracle...?","TWN":"被安排好的奇蹟……？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"자자, 너무 나쁜 쪽만 보지 말고, 좋게 생각하자고~","JPN":"ささ、あまりネガティブに考えず、ポジティブに行きましょう～","ENG":"Now, now, let's not dwell only on the worst-case scenario. Let's look at the bright side.","TWN":"好了，別老往壞處想，往好的一面看嘛～"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"샤레이드를 뒤덮은 뿌리 때문에 도시 대부분의 기능은 마비되었지만.","JPN":"シャレードを覆った根のせいで都市の機能はほとんど麻痺したけど。","ENG":"Most city functions were paralyzed by the roots covering Charade, but...","TWN":"雖然城市大部分機能都因為覆蓋查雷德的根癱瘓了，"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"95% 이상의 시민권자들이 안전 쉘터로 대피를 마쳤어.","JPN":"95％以上の市民権者が安全シェルターに避難できたわ。","ENG":"Over 95% of registered citizens have already evacuated to safe shelters.","TWN":"但95%以上的市民都已撤離到安全庇護所。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그 외 거주민들도 조디악 나이츠의 함선을 이용하여 피난 중이고.","JPN":"その他の居住民も、ゾディアックナイツの艦船に乗って避難しているし。","ENG":"The remaining residents are evacuating using Zodiac Knights ships.","TWN":"其餘居民也正搭乘十二宮騎士團的艦船撤離中。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"리하르트의 매뉴얼대로라면, 물과 식량도 30일까지는 비축분이 있을 거야.","JPN":"リヒャルトのマニュアル通りなら、水や食糧も30日分は備蓄分があるはずよ。","ENG":"According to Richard's manual, we have enough water and food stockpiled for thirty days.","TWN":"依照理查的手冊，水與糧食的儲備量至少還能撐30天。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐, 이 정도면, 그럭저럭 괜찮은 결과 아닐까?","JPN":"この程度ならまあまあいい結果じゃない？","ENG":"Well, all things considered, isn't that a fairly decent outcome?","TWN":"這樣的結果算還可以吧？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"공인 카운터인 자네와 조디악 나이츠가 힘써준 덕분이겠지.","JPN":"公認カウンターである君とゾディアックナイツが力を尽くしてくれたおかげだ。","ENG":"That's thanks to you as an Official Counter, and to the efforts of the Zodiac Knights.","TWN":"這都是多虧了你這位認證制裁者，以及十二宮騎士團的努力吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"과찬입니다, 최고 관리자.","JPN":"もったいないお言葉です、最高管理者。","ENG":"You flatter me, Supreme Administrator.","TWN":"你過獎了，最高管理者。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"저희 기사단은 늘 그렇듯, 민중을 위해서 해야 할 일을 했을 뿐이니까요.","JPN":"私たち騎士団はいつものように、民衆のためにやるべきことをしたまでです。","ENG":"We only did what needed to be done to protect the people.","TWN":"我們騎士團一如既往，只是做了該為民眾做的事而已。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"하지만 한 가지 신경 쓰이는 사람이 있습니다.","JPN":"ですが一人、気になる人がいます。","ENG":"However, there is one person who concerns me.","TWN":"不過，有一個人讓我有些在意。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그게 누구지?","JPN":"誰かね？","ENG":"Who might that be?","TWN":"那是誰呢？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"이름은 모릅니다. 냉철하고 차가운 분위기의 여성이었죠.","JPN":"名前は知りません。落ち着いていて冷たい雰囲気の女性でした。","ENG":"I don't know her name. She was a woman with a calm, cold demeanor.","TWN":"我不知道她的名字，是一位冷靜又冷漠的女性。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"상황은 잘 모르지만, 그녀가 없었다면 우리는 전부 무사하지 못했겠죠.","JPN":"事情は詳しく知りませんが、彼女がいなかったら私たちは皆無事では済まなかったでしょう。","ENG":"I don't know the full circumstances, but without her, none of us would have survived.","TWN":"雖然我不清楚詳細情況，但如果沒有她，我們恐怕無一能倖免。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"하지만 어째선지 그녀는 관리국이 제공하는 피난선에 오르지 않았어요.","JPN":"ですが、なぜか彼女は管理局が提供する艦船に搭乗しませんでした。","ENG":"Yet for some reason, she did not board the evacuation ship provided by the Administration.","TWN":"然而不知為何，她沒有登上管理局提供的撤離船。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"추측컨대 아직 샤레이드에 남아있는 것 같은데…….","JPN":"おそらく、まだシャレードに残っていると思われますが……","ENG":"From what I can tell, she seems to still be in Charade...","TWN":"我推測她應該仍留在查雷德……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그녀의 행방이 걱정되는군요.","JPN":"彼女の行方が心配です。","ENG":"I'm worried about her whereabouts.","TWN":"她的去向實在令人擔心。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"마침내 제 차례가 된 모양이로군요.","JPN":"やっと私の番のようですわね。","ENG":"It seems it's finally my turn.","TWN":"看來終於輪到我了呢。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};